/*!
 * Minimal Bootstrap-compatible helpers for NullAuth development.
 * Production deployments should replace this file with the official self-hosted Bootstrap 5 bundle.
 */
(function () {
  'use strict';

  function Collapse(element) {
    this.element = element;
  }
  Collapse.prototype.toggle = function () {
    this.element.classList.toggle('show');
  };

  function Modal(element) {
    this.element = element;
  }
  Modal.prototype.show = function () {
    this.element.classList.add('show');
    this.element.removeAttribute('aria-hidden');
  };
  Modal.prototype.hide = function () {
    this.element.classList.remove('show');
    this.element.setAttribute('aria-hidden', 'true');
    this.element.dispatchEvent(new Event('hidden.bs.modal'));
  };

  document.addEventListener('click', function (event) {
    var trigger = event.target.closest('[data-bs-toggle="collapse"]');
    if (trigger) {
      var target = document.querySelector(trigger.getAttribute('data-bs-target'));
      if (target) {
        new Collapse(target).toggle();
      }
    }

    var close = event.target.closest('[data-bs-dismiss="modal"]');
    if (close) {
      var modal = close.closest('.modal');
      if (modal) {
        new Modal(modal).hide();
      }
    }
  });

  window.bootstrap = {
    Collapse: Collapse,
    Modal: Modal
  };
}());
